
import React from 'react';

import './home.css';

function Home() {

    const animated = localStorage.getItem("animated");

    if (animated == true) {
        localStorage.setItem("animated", false);
    }

    return (
        <div className="container">
            <div className={ !animated ? "fade-in center-container" : "center-container" } >
                <p className="center-name">Sanket Jadhav</p>
                I am a computer science student passionate about Artificial Intelligence and Robotics
            </div>
        </div>
    );
}

export default Home;
